import{_ as t,o as r,c as o,ak as a}from"./chunks/framework.CRYrbBns.js";const u=JSON.parse('{"title":"Enregistrement des données","description":"","frontmatter":{},"headers":[],"relativePath":"7 - Enregistrement.md","filePath":"7 - Enregistrement.md"}'),d={name:"7 - Enregistrement.md"};function n(s,e,i,c,m,l){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="enregistrement-des-donnees" tabindex="-1">Enregistrement des données <a class="header-anchor" href="#enregistrement-des-donnees" aria-label="Permalink to “Enregistrement des données”">​</a></h1><blockquote><p>Prérequis : <a href="/6 - Création du repo sur huggin-face.html">6 - Création du repo sur huggin-face</a></p></blockquote><h2 id="commande-d-enregistrement" tabindex="-1">Commande d&#39;enregistrement : <a class="header-anchor" href="#commande-d-enregistrement" aria-label="Permalink to “Commande d&#39;enregistrement :”">​</a></h2><p><code>lerobot-record</code><code>--robot.type=so101_follower</code><code>--robot.port=.....</code><code>--robot.id=.....</code><code>--robot.cameras=&quot;{ front: {type: opencv, index_or_path: 1, width: 640, height: 480, fps: 30}, side: {type: opencv, index_or_path: 2, width: 640, height: 480, fps: 30}}&quot;</code><code>--teleop.type=so101_leader</code><code>--teleop.port=....</code><code>--teleop.id=.....</code><code>--display_data=false</code><code>--dataset.repo_id={votre nom d&#39;utilisateur}/record-test</code><code>--dataset.num_episodes=70</code><code>--dataset.single_task=&quot;nom de votre token&quot;</code></p><hr><blockquote><p>Compléter les paramètres : ports USB, noms des robots, paramètres des caméras, nom du dépôt Hugging Face et description de la tâche.</p></blockquote><h2 id="description-de-certains-parametres" tabindex="-1">Description de certains paramètres : <a class="header-anchor" href="#description-de-certains-parametres" aria-label="Permalink to “Description de certains paramètres :”">​</a></h2><table tabindex="0"><thead><tr><th>Arguments de la commande</th><th>Description</th></tr></thead><tbody><tr><td><code>--display_data=false</code></td><td>Permet de ne pas afficher l&#39;interface graphique, si vous souhaitez l&#39;afficher, remplacez &quot;false&quot; par &quot;true&quot;.</td></tr><tr><td><code>--dataset.num_episodes=70</code></td><td>Correspond aux nombres d&#39;épisodes d&#39;enregistrement, un épisode correspond à un mouvement du bras (exemple : attraper une boite). Il faudra donc faire 70 fois le mouvement, afin de permettre à l&#39;IA de s&#39;entrainer correctement.</td></tr></tbody></table><h2 id="enregistrement-controle" tabindex="-1">Enregistrement - contrôle <a class="header-anchor" href="#enregistrement-controle" aria-label="Permalink to “Enregistrement - contrôle”">​</a></h2><p>Une fois l&#39;enregistrement lancé et les caméras positionnées : <strong>Répéter l&#39;ensemble des épisodes</strong>, réalisant la tache souhaitée. Les caméras doivent offrir une bonne vue d&#39;ensemble du robot et de ses mouvements.</p><table tabindex="0"><thead><tr><th>Touche</th><th>Action</th></tr></thead><tbody><tr><td>➡️ (flèche droite)</td><td>Permet de passer à l&#39;enregistrement suivant (après avoir effectué le précèdent)</td></tr><tr><td>⬅️ (flèche gauche)</td><td>Permet de relancer l&#39;épisode actuel, en cas d&#39;erreur.</td></tr><tr><td><code>Echap</code></td><td>Vous permet d&#39;arrêter l&#39;enregistrement</td></tr></tbody></table><p>En cas d&#39;erreur, vous pouvez reprendre directement l&#39;enregistrement, avec la même commande en ajoutant le paramètre : <code>--resume=true</code></p><p>Prochaine étape : <a href="/8 - Entrainement de IA %2B OVH cloud.html">8 - Entrainement de IA + OVH cloud</a></p>',13)])])}const h=t(d,[["render",n]]);export{u as __pageData,h as default};
